INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9eae64ff-65e3-4487-9fe1-4f3ff65f2710',
  '00000000-0000-0000-0000-000000000001',
  $escape$Avoiding Bridge Overload in React Native: JS Thread vs UI Thread$escape$,
  $escape$In React Native, UI components are rendered on the UI thread, while JavaScript logic runs on the JS thread. Bridge overload occurs when the JS thread sends too many updates to the UI thread, causing jank and slowing down the app. To mitigate this, use `AppState` to detect changes and update the UI only when necessary. For example, use `AppState.addEventListener('change', () => this.setState({ ... }))` to update the state only when the app state changes.$escape$,
  $escape$import { AppState } from 'react-native';
AppState.addEventListener('change', () => this.setState({ ... }));$escape$,
  $escape$typescript$escape$,
