INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ba793ab8-b5f5-45ad-98a6-fc7b7b523edb',
  '00000000-0000-0000-0000-000000000001',
  $escape$React Native: Choosing Between Expo Managed and Bare Workflows$escape$,
  $escape$When building React Native apps, you can opt for either the managed or bare workflow. Expo's managed workflow provides a seamless development experience, while the bare workflow offers more control. For production apps, consider using Expo's EAS Build for automated builds and EAS Update for over-the-air (OTA) updates. With EAS Build, create optimized builds for various platforms, and use EAS Update to push updates to your users. For example, to use EAS Update, initialize the Expo SDK, add the EAS Update package, and call `EASUpdate.checkForUpdateAsync()` to check for updates.$escape$,
  $escape$import * as React from 'react';
import { View, Text } from 'react-native';
import { EASUpdate } from 'expo-updates';

const App = () => {
  const checkForUpdate = async () => {
    try {
      const update = await EASUpdate.checkForUpdateAsync();
      if (update.isAvailable) {
        console.log('Update available:', update);
      } else {
        console.log('No update available');
      }
    } catch (error) {
      console.error('Error checking for updates:', error);
    }
  };

  return (
    <View>
      <Text onPress={checkForUpdate}>Check for updates</Text>
    </View>
  );
};

export default App;$escape$,
  $escape$javascript$escape$,
